const request = $('Webhook Copilot Query').first().json;
const verifiedUser = $('🔐 Verify JWT').first().json;
const body = request.body || {};
const config = $input.first().json;

const query = typeof body.query === 'string' ? body.query.trim() : '';
const equipmentCode = typeof body.equipment_code === 'string' ? body.equipment_code.trim().toUpperCase() : '';
const validationType = typeof body.validation_type === 'string' ? body.validation_type.trim().toLowerCase() : '';
const sessionId = typeof body.session_id === 'string' ? body.session_id.trim() : '';
const uuidPattern = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const equipmentPattern = /^[A-Z0-9][A-Z0-9._/-]{0,63}$/;

if (!verifiedUser.id) {
  return [{ json: { error: true, status: 401, message: 'Không lấy được user.id từ bước xác thực' } }];
}
if (!query) {
  return [{ json: { error: true, status: 400, message: 'Thiếu query' } }];
}
if (query.length > Number(config.max_query_length || 6000)) {
  return [{ json: { error: true, status: 400, message: 'query vượt quá độ dài cho phép' } }];
}
if (!equipmentCode || !equipmentPattern.test(equipmentCode)) {
  return [{ json: { error: true, status: 400, message: 'equipment_code không hợp lệ' } }];
}
if (!['iq', 'oq', 'pq'].includes(validationType)) {
  return [{ json: { error: true, status: 400, message: 'validation_type phải là iq, oq hoặc pq' } }];
}
if (sessionId && !uuidPattern.test(sessionId)) {
  return [{ json: { error: true, status: 400, message: 'session_id không đúng định dạng UUID' } }];
}

return [{
  json: {
    error: false,
    user_id: verifiedUser.id,
    user_email: String(verifiedUser.email || ''),
    query,
    equipment_code: equipmentCode,
    validation_type: validationType,
    requested_session_id: sessionId,
    top_k: Number(config.top_k || 8),
    match_threshold: Number(config.match_threshold || 0.4),
    history_limit: Number(config.history_limit || 20),
    citation_text_max: Number(config.citation_text_max || 1200),
    grounding_threshold_pct: Number(config.grounding_threshold_pct || 80)
  }
}];

