const agent = $input.first().json;
const rawOutput = String(agent.output || '').trim();
const citationTextMax = Number($('Parse + Validate').item.json.citation_text_max || 1200);
const threshold = Number($('Parse + Validate').item.json.grounding_threshold_pct || 80);
const uuidPattern = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

function parseJson(value) {
  if (typeof value !== 'string') return value;
  const normalized = value.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  try { return JSON.parse(normalized); } catch { return null; }
}
function collectSources(value, target) {
  const parsed = typeof value === 'string' ? (parseJson(value) || value) : value;
  if (Array.isArray(parsed)) {
    for (const entry of parsed) collectSources(entry, target);
    return;
  }
  if (!parsed || typeof parsed !== 'object') return;
  const candidate = parsed.json && typeof parsed.json === 'object' ? parsed.json : parsed;
  if (candidate.chunk_id && candidate.document_code && (candidate.text || candidate.content)) {
    target.push(candidate);
    return;
  }
  for (const nested of Object.values(parsed)) collectSources(nested, target);
}

const retrievedSources = [];
for (const step of agent.intermediateSteps || []) {
  const toolName = String(step?.action?.tool || step?.tool || '').toLowerCase();
  if (toolName === 'rag_search' || toolName.includes('rag_search')) {
    collectSources(step?.observation ?? step?.output ?? step?.result, retrievedSources);
  }
}

const sourceMap = new Map();
for (const source of retrievedSources) {
  const chunkId = String(source.chunk_id || '').toLowerCase();
  if (uuidPattern.test(chunkId) && !sourceMap.has(chunkId)) sourceMap.set(chunkId, source);
}

const parsedOutput = parseJson(rawOutput);
const candidateAnswer = parsedOutput && typeof parsedOutput.answer === 'string'
  ? parsedOutput.answer.trim()
  : rawOutput;
const answer = candidateAnswer || 'CHƯA CÓ CĂN CỨ SOP ĐÃ DUYỆT để trả lời yêu cầu này.';
const claims = parsedOutput && Array.isArray(parsedOutput.claims) ? parsedOutput.claims : [];
const citedIds = new Set();
let groundedClaims = 0;

for (const claim of claims) {
  const chunkId = typeof claim?.chunk_id === 'string' ? claim.chunk_id.toLowerCase() : '';
  if (uuidPattern.test(chunkId) && sourceMap.has(chunkId)) {
    citedIds.add(chunkId);
    groundedClaims += 1;
  }
}
for (const chunkId of sourceMap.keys()) {
  if (answer.toLowerCase().includes(chunkId)) citedIds.add(chunkId);
}

const totalClaims = claims.length > 0 ? claims.length : 1;
if (claims.length === 0 && citedIds.size > 0) groundedClaims = 1;
const groundedPct = Math.round((groundedClaims / totalClaims) * 100);
const citations = [...citedIds].map((chunkId) => {
  const source = sourceMap.get(chunkId);
  return {
    chunk_id: chunkId,
    document_code: String(source.document_code || ''),
    text: String(source.text || source.content || '').slice(0, citationTextMax)
  };
});
const grounded = citations.length > 0 && groundedPct >= threshold;

return [{
  json: {
    answer,
    citations,
    cited_chunk_ids: citations.map((citation) => citation.chunk_id),
    session_id: String($('PG: Prepare Session + History').item.json.session_id || ''),
    grounded,
    grounded_pct: groundedPct,
    claims_count: totalClaims
  }
}];
